  (2259, 'Wario World', 397614, 'You''re Welcome! No, You''re Not Invited to My New Castle!', 'Beat my game having rescued all 40 Spritelings. I''m such a nice guy! Now get outta here!', 10, 19, NULL, 'AmericanSlacker', 'https://media.retroachievements.org/Badge/449281.png', 613, 566, 117, 'b0bfd919442c140b432798e86f5e0e6f'),
